func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		bestCost := 1e308
		bestIdx := -1

		// evaluate insertion into every existing non-empty route
		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].StationsLen == 0 {
				continue
			}
			if dispatch.Assigns[i].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[i].GenRoute()
				if dispatch.Assigns[i].Cost >= 0 && dispatch.Assigns[i].Cost < bestCost {
